import { Component, h, Prop, Element } from '@stencil/core';

export interface Step {
  progress?: number;
  max?: number;
}

@Component({
  tag: 'wdpr-multi-step-loader',
  shadow: true,
})
export class WdprMultiStepLoader {
  /**
   * Reference to host element
   * @type {HTMLWdprLinearLoaderElement}
   */
  @Element() el: HTMLWdprLinearLoaderElement;

  /**
   * An array of steps
   */
  @Prop() steps: Step[] = [];

  render() {
    return (
      <div class="flex gap-075" role="group" aria-label="Multi-step progress">
        {this.steps.map(step => (
          <wdpr-linear-loader class="flex-1" progress={step.progress ?? 0} max={step.max ?? 100}></wdpr-linear-loader>
        ))}
      </div>
    );
  }
}
